// vector reallocates
for (size_t i = 0; i &lt; oldSize; ++i) {
    new_array[i] = std::move(old_array[i]);
    // if this throws, old_array[i] is moved-from!
}

for (size_t i = 0; i &lt; oldSize; ++i) {
    new_array[i] = std::move_if_noexcept(old_array[i]);
}

template&lt;typename T&gt;
void swap(T&amp; a, T&amp; b) {
    T temp{std::move_if_noexcept(a)};
    a = std::move_if_noexcept(b);
    b = std::move_if_noexcept(temp);
}
